const body = "<!-- ============== HERO ============== -->\n<section class=\"page-hero\">\n  <div class=\"glow\" aria-hidden=\"true\"></div>\n  <div class=\"container reveal\">\n    <a href=\"/portfolio\" class=\"btn btn-ghost\" style=\"padding:0;color:var(--mist-60);\">← Back to portfolio</a>\n    <div style=\"display:flex;gap:.6rem;flex-wrap:wrap;margin-top:1.25rem;\">\n      <span class=\"badge\"><span class=\"uae-flag-bar\"><span class=\"red\"></span><span class=\"green\"></span><span class=\"white\"></span><span class=\"black\"></span></span>Built for the UAE</span>\n      <span class=\"badge badge-success\">● Flagship platform</span>\n      <span class=\"badge\">On-prem · Air-gapped</span>\n      <span class=\"badge\">RBAC · Audit-grade</span>\n    </div>\n    <h1 style=\"margin-top:1.25rem;max-width:20ch;\">AI that reads your documents — and shows its work.</h1>\n    <p class=\"lead\" style=\"max-width:64ch;\">Agentic retrieval-augmented generation for organisations that can't trade data for convenience. Sovereign or air-gapped deployment, role-based access on every chunk, citations on every claim, and a complete audit trail of what the model saw and did.</p>\n\n    <div style=\"display:flex;gap:1rem;margin-top:1.5rem;flex-wrap:wrap;\">\n      <a href=\"/contact\" class=\"btn btn-primary\">Book a private demo\n        <svg class=\"arrow\" viewBox=\"0 0 24 24\" fill=\"none\" stroke=\"currentColor\" stroke-width=\"2\"><path d=\"M5 12h14M13 5l7 7-7 7\"/></svg>\n      </a>\n      <a href=\"#console\" class=\"btn btn-outline\">See the console ↓</a>\n    </div>\n\n    <div class=\"launch-stats\">\n      <div class=\"launch-stat\"><div class=\"v\"><span data-count=\"6\" data-suffix=\"\">0</span></div><div class=\"l\">live deployments</div></div>\n      <div class=\"launch-stat\"><div class=\"v\"><span data-count=\"2.4\" data-suffix=\"M docs\">0M docs</span></div><div class=\"l\">indexed across tenants</div></div>\n      <div class=\"launch-stat\"><div class=\"v\"><span data-count=\"94\" data-suffix=\"%\">0%</span></div><div class=\"l\">citation precision · benchmark</div></div>\n      <div class=\"launch-stat\"><div class=\"v\"><span data-count=\"1.4\" data-suffix=\"s p50\">0s p50</span></div><div class=\"l\">end-to-end latency</div></div>\n    </div>\n  </div>\n</section>\n\n<!-- ============== CONSOLE / CHAT MOCKUP ============== -->\n<section class=\"section\" id=\"console\" style=\"padding-top:0;\">\n  <div class=\"container reveal\">\n    <div class=\"section-head\" style=\"margin-bottom:2rem;\">\n      <span class=\"eyebrow\">The console</span>\n      <h2 style=\"margin-top:1rem;max-width:22ch;\">Ask. Verify. Trust the answer.</h2>\n      <p class=\"lead\" style=\"max-width:62ch;\">Every claim cites the source. Every source is a real document the user is allowed to see. Tools, planning steps, and retrievals are visible and auditable — not hidden in a black box.</p>\n    </div>\n\n    <div class=\"console\">\n\n      <!-- chrome -->\n      <div class=\"ck-chrome\">\n        <div class=\"dots\"><i></i><i></i><i></i></div>\n        <div class=\"url\"><span class=\"lock\">●</span> ai.ministry.gov.ae <span style=\"color:rgba(255,255,255,0.3);margin-left:auto;\">/ workspace · policy</span></div>\n        <div class=\"actions\"><span>⌘K</span><span>?</span></div>\n      </div>\n\n      <!-- body -->\n      <div class=\"ck-body\">\n\n        <!-- sidebar -->\n        <aside class=\"ck-side\">\n          <div class=\"org\">\n            <span class=\"mark\">M</span>\n            <div><b>Ministry · Policy</b><span>3,420 docs · 14 users</span></div>\n          </div>\n          <div class=\"new-btn\">+ new conversation</div>\n          <div class=\"lbl\">Today</div>\n          <div class=\"conv active\">\n            <span>Federal procurement thresholds</span>\n            <span class=\"meta\">12:42 · 6 turns</span>\n          </div>\n          <div class=\"conv\">\n            <span>VAT exemption for charities</span>\n            <span class=\"meta\">10:18 · 3 turns</span>\n          </div>\n          <div class=\"lbl\">This week</div>\n          <div class=\"conv\"><span>Data retention regulation 2024</span><span class=\"meta\">tue · 11 turns</span></div>\n          <div class=\"conv\"><span>Cross-border tax treaty draft</span><span class=\"meta\">mon · 4 turns</span></div>\n          <div class=\"conv\"><span>Tender evaluation criteria</span><span class=\"meta\">mon · 8 turns</span></div>\n          <div class=\"lbl\">Workspaces</div>\n          <div class=\"conv\"><span># Policy</span></div>\n          <div class=\"conv\"><span># Legal</span></div>\n          <div class=\"conv\"><span># Procurement</span></div>\n        </aside>\n\n        <!-- main -->\n        <div class=\"ck-main\">\n\n          <div class=\"ck-top\">\n            <div>\n              <h3>Federal procurement thresholds</h3>\n              <div class=\"meta\">Workspace · Policy · 3,420 docs · last updated 2h ago</div>\n            </div>\n            <div class=\"right\">\n              <span class=\"pill-mini live\"><i></i>SECURE</span>\n              <span class=\"pill-mini\">v2.1 · on-prem</span>\n            </div>\n          </div>\n\n          <div class=\"ck-stream\">\n\n            <!-- user q -->\n            <div class=\"msg-user\">\n              <div class=\"who\">Fatima · policy analyst</div>\n              What is the current threshold for direct procurement under federal regulation, and how does it differ from the emirate-level rules in Dubai?\n            </div>\n\n            <!-- agent -->\n            <div class=\"msg-agent\">\n              <div class=\"av\">\n                <svg width=\"18\" height=\"18\" viewBox=\"0 0 24 24\" fill=\"none\" stroke=\"currentColor\" stroke-width=\"2\"><circle cx=\"12\" cy=\"12\" r=\"3\"/><path d=\"M19 12a7 7 0 0 0-14 0\"/><path d=\"M12 2v3M12 19v3M2 12h3M19 12h3\"/></svg>\n              </div>\n              <div class=\"body\">\n                <div class=\"who\">Assistant <span class=\"ml\">model · llama-3 70B · on-prem</span></div>\n\n                <!-- agent steps -->\n                <div class=\"steps\">\n                  <div class=\"step done\">\n                    <div class=\"ico\"></div>\n                    <div class=\"lbl\"><b>Plan</b> <span>· decomposed into 2 sub-questions: federal threshold; Dubai variation</span></div>\n                    <div class=\"ms\">82ms</div>\n                  </div>\n                  <div class=\"step done\">\n                    <div class=\"ico\"></div>\n                    <div class=\"lbl\"><b>Retrieve · federal regulation</b> <span>· 4 chunks · workspace: Policy · ACL passed</span></div>\n                    <div class=\"ms\">214ms</div>\n                  </div>\n                  <div class=\"step done\">\n                    <div class=\"ico\"></div>\n                    <div class=\"lbl\"><b>Retrieve · Dubai amendments</b> <span>· 3 chunks · workspace: Policy</span></div>\n                    <div class=\"ms\">198ms</div>\n                  </div>\n                  <div class=\"step done\">\n                    <div class=\"ico\"></div>\n                    <div class=\"lbl\"><b>Tool · table-lookup</b> <span>· threshold-table.csv · row: 2024 amendments</span></div>\n                    <div class=\"ms\">66ms</div>\n                  </div>\n                  <div class=\"step done\">\n                    <div class=\"ico\"></div>\n                    <div class=\"lbl\"><b>Synthesise &amp; verify citations</b> <span>· 6 claims · 6 supported</span></div>\n                    <div class=\"ms\">312ms</div>\n                  </div>\n                </div>\n\n                <div class=\"answer\">\n                  <p>Under federal regulation, direct procurement (without a competitive process) is permitted for contracts up to <b>AED 200,000</b>, raised from AED 150,000 in the 2024 amendments<span class=\"cite\">¹</span>. Procurement officers must still document a single-source justification.</p>\n                  <p>Dubai's emirate-level rules diverge in two ways<span class=\"cite\">²</span><span class=\"cite\">³</span>:</p>\n                  <ul>\n                    <li>The threshold is set lower at <b>AED 100,000</b> for departments under Dubai Government Excellence Programme.</li>\n                    <li>Above that, framework-agreement procurement is available for repeat purchases of routine supplies, which the federal rules do not codify.</li>\n                  </ul>\n                  <p>For cross-jurisdictional procurement, the stricter ceiling applies — the federal rule only sets the upper bound<span class=\"cite\">⁴</span>.</p>\n                  <div style=\"margin-top:1rem;\">\n                    <span class=\"tool-chip\"><svg viewBox=\"0 0 24 24\" fill=\"none\" stroke=\"currentColor\" stroke-width=\"2\"><path d=\"M21 15v4a2 2 0 0 1-2 2H5a2 2 0 0 1-2-2v-4\"/><polyline points=\"7 10 12 15 17 10\"/><line x1=\"12\" y1=\"15\" x2=\"12\" y2=\"3\"/></svg>Export memo</span>\n                    <span class=\"tool-chip\"><svg viewBox=\"0 0 24 24\" fill=\"none\" stroke=\"currentColor\" stroke-width=\"2\"><path d=\"M22 2 11 13\"/><path d=\"M22 2 15 22l-4-9-9-4z\"/></svg>Send to legal</span>\n                    <span class=\"tool-chip\"><svg viewBox=\"0 0 24 24\" fill=\"none\" stroke=\"currentColor\" stroke-width=\"2\"><path d=\"M21 11.5a8.38 8.38 0 0 1-7.6 8.5 8.38 8.38 0 0 1-3.8-.9L3 21l1.9-5.7a8.5 8.5 0 1 1 16.1-3.8z\"/></svg>Ask follow-up</span>\n                  </div>\n                </div>\n              </div>\n            </div>\n\n          </div>\n\n          <!-- composer -->\n          <div class=\"ck-composer\">\n            <div class=\"row\">\n              <button class=\"attach\" aria-label=\"attach\">\n                <svg width=\"14\" height=\"14\" viewBox=\"0 0 24 24\" fill=\"none\" stroke=\"currentColor\" stroke-width=\"2\"><path d=\"M21.44 11.05l-9.19 9.19a6 6 0 0 1-8.49-8.49l9.19-9.19a4 4 0 0 1 5.66 5.66l-9.2 9.19a2 2 0 0 1-2.83-2.83l8.49-8.48\"/></svg>\n              </button>\n              <input placeholder=\"Ask a follow-up · cite a section · or upload a draft to compare\" />\n              <button class=\"send\" aria-label=\"send\">\n                <svg width=\"14\" height=\"14\" viewBox=\"0 0 24 24\" fill=\"none\" stroke=\"currentColor\" stroke-width=\"2.5\"><path d=\"M22 2 11 13\"/><path d=\"M22 2 15 22l-4-9-9-4z\"/></svg>\n              </button>\n            </div>\n            <div class=\"ck-foot\">\n              <span class=\"sg\">↗ summarize this answer</span>\n              <span class=\"sg\">⌘ /reset planning</span>\n              <span class=\"sg\">⇧ compare against draft</span>\n              <span class=\"sg\" style=\"margin-left:auto; color:rgba(122,240,184,0.7); border-color:rgba(122,240,184,0.25);\">all retrieval ACL-checked · 0 leaks</span>\n            </div>\n          </div>\n\n        </div>\n\n        <!-- citations panel -->\n        <aside class=\"ck-cite\">\n          <div class=\"hd\">Sources · 4 cited · 7 retrieved</div>\n          <div class=\"src\">\n            <div class=\"top\"><span class=\"num\">1</span><b>Federal Decree-Law on Public Procurement · 2024 amendments</b></div>\n            <div class=\"meta\">law-2024-procurement.pdf · § 14 · p. 22</div>\n            <div class=\"snip\">\"…direct procurement is permitted for contracts not exceeding two hundred thousand UAE Dirhams, provided a single-source justification is on file…\"</div>\n            <div class=\"scoreline\"><span>relevance</span><div class=\"bar\"><i style=\"width:96%\"></i></div><span>0.96</span></div>\n          </div>\n          <div class=\"src\">\n            <div class=\"top\"><span class=\"num\">2</span><b>Dubai Government Procurement Manual</b></div>\n            <div class=\"meta\">dgep-manual-2024.pdf · § 4.2 · p. 17</div>\n            <div class=\"snip\">\"…departments operating under the Excellence Programme apply a threshold of AED 100,000 for direct purchase…\"</div>\n            <div class=\"scoreline\"><span>relevance</span><div class=\"bar\"><i style=\"width:88%\"></i></div><span>0.88</span></div>\n          </div>\n          <div class=\"src\">\n            <div class=\"top\"><span class=\"num\">3</span><b>DGEP framework-agreement guidance</b></div>\n            <div class=\"meta\">dgep-framework.pdf · § 6 · p. 11</div>\n            <div class=\"snip\">\"…framework agreements may be entered into for routine supplies where annual demand exceeds twelve recurring orders…\"</div>\n            <div class=\"scoreline\"><span>relevance</span><div class=\"bar\"><i style=\"width:81%\"></i></div><span>0.81</span></div>\n          </div>\n          <div class=\"src\">\n            <div class=\"top\"><span class=\"num\">4</span><b>Cross-jurisdiction circular · Q3 2024</b></div>\n            <div class=\"meta\">circ-2024-q3.pdf · § 2 · p. 4</div>\n            <div class=\"snip\">\"…where federal and emirate thresholds differ, the lower ceiling applies for the procuring department…\"</div>\n            <div class=\"scoreline\"><span>relevance</span><div class=\"bar\"><i style=\"width:74%\"></i></div><span>0.74</span></div>\n          </div>\n        </aside>\n\n      </div>\n    </div>\n\n    <p style=\"text-align:center; color:var(--mist-60); font-size:.85rem; margin-top:1.5rem; font-family:'JetBrains Mono';\">A representative session. Document names, citations and figures shown are illustrative — every deployment runs on the client's own corpus, behind their own perimeter.</p>\n  </div>\n</section>\n\n<!-- ============== AGENT LOOP ============== -->\n<section class=\"section\">\n  <div class=\"container\">\n    <div class=\"section-head reveal\" style=\"margin-bottom:2.5rem;\">\n      <span class=\"eyebrow\">How it thinks</span>\n      <h2 style=\"margin-top:1rem;max-width:22ch;\">A loop, not a single shot.</h2>\n      <p class=\"lead\" style=\"max-width:62ch;\">Naive RAG retrieves once and hopes for the best. Our agent plans, retrieves, calls tools, verifies its own citations, and re-plans when the evidence is thin. Every step is logged.</p>\n    </div>\n\n    <div class=\"loop reveal\">\n      <svg viewBox=\"0 0 1100 360\" class=\"loop-svg\" xmlns=\"http://www.w3.org/2000/svg\">\n        <defs>\n          <marker id=\"lp-arr\" viewBox=\"0 0 10 10\" refX=\"9\" refY=\"5\" markerWidth=\"7\" markerHeight=\"7\" orient=\"auto-start-reverse\"><path d=\"M0 0 L10 5 L0 10 z\" fill=\"rgba(122,240,184,0.55)\"/></marker>\n          <linearGradient id=\"lp-g\" x1=\"0\" x2=\"1\" y1=\"0\" y2=\"0\"><stop offset=\"0\" stop-color=\"#19C37D\"/><stop offset=\"1\" stop-color=\"#7AF0B8\"/></linearGradient>\n        </defs>\n\n        <!-- input box -->\n        <g>\n          <rect x=\"20\" y=\"140\" width=\"160\" height=\"80\" rx=\"12\" fill=\"rgba(91,141,239,0.06)\" stroke=\"rgba(91,141,239,0.4)\"/>\n          <text x=\"100\" y=\"170\" text-anchor=\"middle\" fill=\"#9EBAF6\" font-family=\"'Space Grotesk'\" font-weight=\"700\" font-size=\"14\">User question</text>\n          <text x=\"100\" y=\"192\" text-anchor=\"middle\" fill=\"rgba(255,255,255,0.55)\" font-family=\"'JetBrains Mono'\" font-size=\"10\">+ workspace · role</text>\n          <text x=\"100\" y=\"208\" text-anchor=\"middle\" fill=\"rgba(255,255,255,0.45)\" font-family=\"'JetBrains Mono'\" font-size=\"9\">+ conversation history</text>\n        </g>\n\n        <!-- 5 loop nodes around -->\n        <g font-family=\"'Space Grotesk'\" font-weight=\"700\" font-size=\"13\">\n          <!-- 1 plan -->\n          <circle cx=\"320\" cy=\"80\" r=\"62\" fill=\"rgba(25,195,125,0.06)\" stroke=\"rgba(25,195,125,0.45)\" stroke-width=\"1.5\"/>\n          <text x=\"320\" y=\"62\" text-anchor=\"middle\" fill=\"rgba(122,240,184,0.6)\" font-family=\"'JetBrains Mono'\" font-size=\"9\">01</text>\n          <text x=\"320\" y=\"80\" text-anchor=\"middle\" fill=\"#7AF0B8\">Plan</text>\n          <text x=\"320\" y=\"98\" text-anchor=\"middle\" font-family=\"Inter\" font-size=\"9.5\" fill=\"rgba(255,255,255,0.6)\">decompose · scope</text>\n\n          <!-- 2 retrieve -->\n          <circle cx=\"540\" cy=\"60\" r=\"62\" fill=\"rgba(25,195,125,0.06)\" stroke=\"rgba(25,195,125,0.45)\" stroke-width=\"1.5\"/>\n          <text x=\"540\" y=\"42\" text-anchor=\"middle\" fill=\"rgba(122,240,184,0.6)\" font-family=\"'JetBrains Mono'\" font-size=\"9\">02</text>\n          <text x=\"540\" y=\"60\" text-anchor=\"middle\" fill=\"#7AF0B8\">Retrieve</text>\n          <text x=\"540\" y=\"78\" text-anchor=\"middle\" font-family=\"Inter\" font-size=\"9.5\" fill=\"rgba(255,255,255,0.6)\">hybrid · ACL-aware</text>\n\n          <!-- 3 act / tools -->\n          <circle cx=\"760\" cy=\"80\" r=\"62\" fill=\"rgba(25,195,125,0.06)\" stroke=\"rgba(25,195,125,0.45)\" stroke-width=\"1.5\"/>\n          <text x=\"760\" y=\"62\" text-anchor=\"middle\" fill=\"rgba(122,240,184,0.6)\" font-family=\"'JetBrains Mono'\" font-size=\"9\">03</text>\n          <text x=\"760\" y=\"80\" text-anchor=\"middle\" fill=\"#7AF0B8\">Act</text>\n          <text x=\"760\" y=\"98\" text-anchor=\"middle\" font-family=\"Inter\" font-size=\"9.5\" fill=\"rgba(255,255,255,0.6)\">tools · DBs · APIs</text>\n\n          <!-- 4 synthesise -->\n          <circle cx=\"760\" cy=\"280\" r=\"62\" fill=\"rgba(25,195,125,0.06)\" stroke=\"rgba(25,195,125,0.45)\" stroke-width=\"1.5\"/>\n          <text x=\"760\" y=\"262\" text-anchor=\"middle\" fill=\"rgba(122,240,184,0.6)\" font-family=\"'JetBrains Mono'\" font-size=\"9\">04</text>\n          <text x=\"760\" y=\"280\" text-anchor=\"middle\" fill=\"#7AF0B8\">Synthesise</text>\n          <text x=\"760\" y=\"298\" text-anchor=\"middle\" font-family=\"Inter\" font-size=\"9.5\" fill=\"rgba(255,255,255,0.6)\">draft · cite · ground</text>\n\n          <!-- 5 verify -->\n          <circle cx=\"540\" cy=\"300\" r=\"62\" fill=\"rgba(25,195,125,0.06)\" stroke=\"rgba(25,195,125,0.45)\" stroke-width=\"1.5\"/>\n          <text x=\"540\" y=\"282\" text-anchor=\"middle\" fill=\"rgba(122,240,184,0.6)\" font-family=\"'JetBrains Mono'\" font-size=\"9\">05</text>\n          <text x=\"540\" y=\"300\" text-anchor=\"middle\" fill=\"#7AF0B8\">Verify</text>\n          <text x=\"540\" y=\"318\" text-anchor=\"middle\" font-family=\"Inter\" font-size=\"9.5\" fill=\"rgba(255,255,255,0.6)\">claims ↔ sources</text>\n\n          <!-- 6 reflect -->\n          <circle cx=\"320\" cy=\"280\" r=\"62\" fill=\"rgba(245,197,107,0.06)\" stroke=\"rgba(245,197,107,0.4)\" stroke-width=\"1.5\"/>\n          <text x=\"320\" y=\"262\" text-anchor=\"middle\" fill=\"rgba(245,197,107,0.7)\" font-family=\"'JetBrains Mono'\" font-size=\"9\">06</text>\n          <text x=\"320\" y=\"280\" text-anchor=\"middle\" fill=\"#F5C56B\">Reflect</text>\n          <text x=\"320\" y=\"298\" text-anchor=\"middle\" font-family=\"Inter\" font-size=\"9.5\" fill=\"rgba(255,255,255,0.6)\">re-plan if thin</text>\n        </g>\n\n        <!-- arrows around the loop -->\n        <g stroke=\"url(#lp-g)\" stroke-width=\"1.8\" fill=\"none\" marker-end=\"url(#lp-arr)\">\n          <path d=\"M180 180 L 270 110\"/>\n          <path d=\"M380 75  L 478 65\"/>\n          <path d=\"M598 65  L 700 75\"/>\n          <path d=\"M788 138 L 788 222\"/>\n          <path d=\"M700 295 L 600 297\"/>\n          <path d=\"M480 305 L 380 295\"/>\n          <!-- reflect back to plan -->\n          <path d=\"M310 220 L 310 142\" stroke-dasharray=\"4 4\"/>\n        </g>\n\n        <!-- output box -->\n        <g>\n          <rect x=\"920\" y=\"140\" width=\"160\" height=\"80\" rx=\"12\" fill=\"rgba(122,240,184,0.06)\" stroke=\"rgba(122,240,184,0.45)\"/>\n          <text x=\"1000\" y=\"170\" text-anchor=\"middle\" fill=\"#7AF0B8\" font-family=\"'Space Grotesk'\" font-weight=\"700\" font-size=\"14\">Cited answer</text>\n          <text x=\"1000\" y=\"192\" text-anchor=\"middle\" fill=\"rgba(255,255,255,0.55)\" font-family=\"'JetBrains Mono'\" font-size=\"10\">+ traces · audit log</text>\n          <text x=\"1000\" y=\"208\" text-anchor=\"middle\" fill=\"rgba(255,255,255,0.45)\" font-family=\"'JetBrains Mono'\" font-size=\"9\">+ confidence · sources</text>\n        </g>\n        <g stroke=\"rgba(122,240,184,0.55)\" stroke-width=\"1.8\" fill=\"none\" marker-end=\"url(#lp-arr)\">\n          <path d=\"M822 280 C 870 240, 890 200, 920 188\"/>\n        </g>\n      </svg>\n    </div>\n  </div>\n</section>\n\n<!-- ============== ANATOMY ============== -->\n<section class=\"section\">\n  <div class=\"container\">\n    <div class=\"section-head reveal\" style=\"margin-bottom:3.5rem;\">\n      <span class=\"eyebrow\">Anatomy</span>\n      <h2 style=\"margin-top:1rem;max-width:22ch;\">Five capabilities. One platform. No surprises.</h2>\n      <p class=\"lead\" style=\"max-width:62ch;\">Each layer is engineered for the same outcome: an answer you can stake your reputation on.</p>\n    </div>\n\n    <div class=\"module-stack reveal-stagger\">\n\n      <!-- 01 INGESTION -->\n      <div class=\"module\">\n        <div class=\"module-text\">\n          <div class=\"num\">01 — Ingestion &amp; connectors</div>\n          <h3>Bring your own corpus — wherever it lives.</h3>\n          <p class=\"lead\">Native connectors to the document stores your organisation already runs. Incremental sync, OCR, layout-aware parsing for tables and diagrams, and per-source ACL preservation.</p>\n          <ul>\n            <li>SharePoint · Google Drive · Confluence · file shares</li>\n            <li>Email archives · ticket systems · SQL databases</li>\n            <li>OCR for scanned docs · PDF table extraction · diagram captioning</li>\n            <li>Per-document permission inheritance — never re-permission anything</li>\n            <li>Incremental sync · delta-only re-indexing</li>\n          </ul>\n        </div>\n        <div class=\"module-visual\">\n          <div class=\"mv-bar\"><div class=\"dots\"><i></i><i></i><i></i></div><span>Sources · sync status</span></div>\n          <div class=\"mv-body\">\n            <table class=\"src-tbl\">\n              <thead><tr><th>Source</th><th>Type</th><th>Docs</th><th>Last sync</th><th>Status</th></tr></thead>\n              <tbody>\n                <tr><td><div class=\"nm\"><span class=\"lo\">SP</span>Policy SharePoint</div></td><td>SharePoint</td><td class=\"ct\">14,820</td><td class=\"ct\">2m ago</td><td><span class=\"stat-tag ok\">live</span></td></tr>\n                <tr><td><div class=\"nm\"><span class=\"lo\">GD</span>Legal · Drive</div></td><td>Google Drive</td><td class=\"ct\">8,402</td><td class=\"ct\">14m ago</td><td><span class=\"stat-tag ok\">live</span></td></tr>\n                <tr><td><div class=\"nm\"><span class=\"lo\">CF</span>Operations · Confluence</div></td><td>Confluence</td><td class=\"ct\">2,108</td><td class=\"ct\">42m ago</td><td><span class=\"stat-tag sync\">syncing</span></td></tr>\n                <tr><td><div class=\"nm\"><span class=\"lo\">FS</span>Archive · NAS</div></td><td>SMB share</td><td class=\"ct\">38,990</td><td class=\"ct\">1h ago</td><td><span class=\"stat-tag ok\">live</span></td></tr>\n                <tr><td><div class=\"nm\"><span class=\"lo\">DB</span>Procurement · Postgres</div></td><td>SQL</td><td class=\"ct\">182k rows</td><td class=\"ct\">3h ago</td><td><span class=\"stat-tag ok\">live</span></td></tr>\n                <tr><td><div class=\"nm\"><span class=\"lo\">EM</span>Inbox · Exchange</div></td><td>Email</td><td class=\"ct\">62,401</td><td class=\"ct\">6h ago</td><td><span class=\"stat-tag warn\">re-auth</span></td></tr>\n              </tbody>\n            </table>\n          </div>\n        </div>\n      </div>\n\n      <!-- 02 SECURITY -->\n      <div class=\"module flip\">\n        <div class=\"module-text\">\n          <div class=\"num\">02 — Security &amp; isolation</div>\n          <h3>Built for organisations that can't trade data for convenience.</h3>\n          <p class=\"lead\">On-prem, sovereign-cloud or air-gapped. Document permissions enforced at the chunk level — the model can only retrieve what the asking user is already allowed to see. Nothing leaves your perimeter.</p>\n          <ul>\n            <li>On-prem · sovereign-cloud · air-gapped deployment</li>\n            <li>Chunk-level ACLs · per-user, per-workspace, per-tag</li>\n            <li>PII detection &amp; redaction at ingest and at output</li>\n            <li>SSO · SAML · LDAP · Active Directory integration</li>\n            <li>End-to-end encryption · KMS-managed keys</li>\n          </ul>\n        </div>\n        <div class=\"module-visual\">\n          <div class=\"mv-bar\"><div class=\"dots\"><i></i><i></i><i></i></div><span>Security posture · production</span></div>\n          <div class=\"mv-body\">\n            <div class=\"sec-grid\">\n              <div class=\"sec-card\">\n                <div class=\"hd\"><div class=\"ic\"><svg width=\"14\" height=\"14\" viewBox=\"0 0 24 24\" fill=\"none\" stroke=\"currentColor\" stroke-width=\"2\"><path d=\"M12 22s8-4 8-10V5l-8-3-8 3v7c0 6 8 10 8 10z\"/></svg></div><b>Deployment</b></div>\n                <div class=\"meta\">On-prem · single-tenant · client KMS</div>\n                <div class=\"stat\">Air-gapped</div>\n              </div>\n              <div class=\"sec-card\">\n                <div class=\"hd\"><div class=\"ic\"><svg width=\"14\" height=\"14\" viewBox=\"0 0 24 24\" fill=\"none\" stroke=\"currentColor\" stroke-width=\"2\"><rect x=\"3\" y=\"11\" width=\"18\" height=\"11\" rx=\"2\"/><path d=\"M7 11V7a5 5 0 0 1 10 0v4\"/></svg></div><b>ACL enforcement</b></div>\n                <div class=\"meta\">Chunk-level · per-user · per-tag</div>\n                <div class=\"stat\">14,820 rules</div>\n              </div>\n              <div class=\"sec-card\">\n                <div class=\"hd\"><div class=\"ic\"><svg width=\"14\" height=\"14\" viewBox=\"0 0 24 24\" fill=\"none\" stroke=\"currentColor\" stroke-width=\"2\"><circle cx=\"12\" cy=\"12\" r=\"9\"/><path d=\"M9 12l2 2 4-4\"/></svg></div><b>PII redaction</b></div>\n                <div class=\"meta\">At ingest &amp; at output · 18 entity types</div>\n                <div class=\"stat\">99.4% recall</div>\n              </div>\n              <div class=\"sec-card\">\n                <div class=\"hd\"><div class=\"ic\"><svg width=\"14\" height=\"14\" viewBox=\"0 0 24 24\" fill=\"none\" stroke=\"currentColor\" stroke-width=\"2\"><path d=\"M3 12h4l2-7 4 14 2-7h6\"/></svg></div><b>Audit trail</b></div>\n                <div class=\"meta\">Every retrieval · every tool call</div>\n                <div class=\"stat\">7-year retention</div>\n              </div>\n              <div class=\"sec-card\">\n                <div class=\"hd\"><div class=\"ic\"><svg width=\"14\" height=\"14\" viewBox=\"0 0 24 24\" fill=\"none\" stroke=\"currentColor\" stroke-width=\"2\"><path d=\"M12 2 4 6v6c0 5.5 3.8 10.7 8 12 4.2-1.3 8-6.5 8-12V6z\"/></svg></div><b>Identity</b></div>\n                <div class=\"meta\">SSO · SAML · MFA enforced</div>\n                <div class=\"stat\">100% SSO</div>\n              </div>\n              <div class=\"sec-card\">\n                <div class=\"hd\"><div class=\"ic\"><svg width=\"14\" height=\"14\" viewBox=\"0 0 24 24\" fill=\"none\" stroke=\"currentColor\" stroke-width=\"2\"><circle cx=\"12\" cy=\"12\" r=\"9\"/><path d=\"M3 12h18M12 3a14 14 0 0 1 0 18M12 3a14 14 0 0 0 0 18\"/></svg></div><b>Egress</b></div>\n                <div class=\"meta\">No outbound · model weights local</div>\n                <div class=\"stat\">0 leaks</div>\n              </div>\n            </div>\n          </div>\n        </div>\n      </div>\n\n      <!-- 03 RETRIEVAL -->\n      <div class=\"module\">\n        <div class=\"module-text\">\n          <div class=\"num\">03 — Hybrid retrieval &amp; ranking</div>\n          <h3>Find the right paragraph — not the closest-sounding one.</h3>\n          <p class=\"lead\">Dense embedding retrieval for semantic recall, BM25 for keyword precision, cross-encoder reranking for final ordering. Retrieval is workspace-scoped, ACL-checked, and aware of conversation context.</p>\n          <ul>\n            <li>Dense (E5 / bge) + sparse (BM25) hybrid retrieval</li>\n            <li>Cross-encoder reranking · top-100 → top-8</li>\n            <li>Conversation-aware query rewriting</li>\n            <li>Per-workspace tuning · custom embeddings on request</li>\n            <li>Sub-200ms p50 across 1M+ chunks</li>\n          </ul>\n        </div>\n        <div class=\"module-visual\">\n          <div class=\"mv-bar\"><div class=\"dots\"><i></i><i></i><i></i></div><span>Retrieval · Q&amp;A benchmark</span></div>\n          <div class=\"mv-body\">\n            <div class=\"eval-grid\">\n              <div class=\"eval-card\">\n                <div class=\"hd\"><b>Recall@10</b><span class=\"pct\">94.2%</span></div>\n                <div class=\"bar\"><i style=\"width:94%\"></i></div>\n                <div class=\"meta\">+18pp over dense-only baseline</div>\n              </div>\n              <div class=\"eval-card\">\n                <div class=\"hd\"><b>MRR</b><span class=\"pct\">0.81</span></div>\n                <div class=\"bar\"><i style=\"width:81%\"></i></div>\n                <div class=\"meta\">Mean reciprocal rank · top-cited</div>\n              </div>\n              <div class=\"eval-card\">\n                <div class=\"hd\"><b>Citation precision</b><span class=\"pct\">93.8%</span></div>\n                <div class=\"bar\"><i style=\"width:94%\"></i></div>\n                <div class=\"meta\">Claims supported by their cited source</div>\n              </div>\n              <div class=\"eval-card\">\n                <div class=\"hd\"><b>Hallucination rate</b><span class=\"pct\" style=\"color:#7AF0B8;\">0.6%</span></div>\n                <div class=\"bar\"><i style=\"width:6%\"></i></div>\n                <div class=\"meta\">Unsupported claims · self-verify catches</div>\n              </div>\n              <div class=\"eval-card\">\n                <div class=\"hd\"><b>p50 latency</b><span class=\"pct\">1.4s</span></div>\n                <div class=\"bar\"><i style=\"width:35%\"></i></div>\n                <div class=\"meta\">End-to-end · including planning &amp; verify</div>\n              </div>\n              <div class=\"eval-card\">\n                <div class=\"hd\"><b>p99 latency</b><span class=\"pct\">3.8s</span></div>\n                <div class=\"bar\"><i style=\"width:62%\"></i></div>\n                <div class=\"meta\">Even with re-plan loops</div>\n              </div>\n            </div>\n          </div>\n        </div>\n      </div>\n\n      <!-- 04 AGENTS / TOOLS -->\n      <div class=\"module flip\">\n        <div class=\"module-text\">\n          <div class=\"num\">04 — Agents &amp; tools</div>\n          <h3>Beyond Q&amp;A — workflows that finish the work.</h3>\n          <p class=\"lead\">Custom tools your domain needs: structured table queries, calculator, calendar, ticket creation, code execution in a sandbox. The agent decides when to call them, you decide which exist.</p>\n          <ul>\n            <li>Tool-use protocol · custom function calling</li>\n            <li>Sandboxed code execution for reproducible analysis</li>\n            <li>Structured output: JSON · forms · spreadsheets</li>\n            <li>Multi-step workflows: retrieve → compute → draft → route</li>\n            <li>Human-in-the-loop checkpoints on sensitive actions</li>\n          </ul>\n        </div>\n        <div class=\"module-visual\">\n          <div class=\"mv-bar\"><div class=\"dots\"><i></i><i></i><i></i></div><span>Tools · in this workspace</span></div>\n          <div class=\"mv-body\">\n            <div class=\"sec-grid\">\n              <div class=\"sec-card\">\n                <div class=\"hd\"><div class=\"ic\"><svg width=\"14\" height=\"14\" viewBox=\"0 0 24 24\" fill=\"none\" stroke=\"currentColor\" stroke-width=\"2\"><rect x=\"3\" y=\"3\" width=\"18\" height=\"18\" rx=\"2\"/><path d=\"M3 9h18M9 3v18\"/></svg></div><b>table-lookup</b></div>\n                <div class=\"meta\">Query a structured CSV / DB by row · column</div>\n                <div class=\"stat\" style=\"font-size:.85rem; color:rgba(255,255,255,0.6); font-family:'JetBrains Mono';\">used 1,402×</div>\n              </div>\n              <div class=\"sec-card\">\n                <div class=\"hd\"><div class=\"ic\"><svg width=\"14\" height=\"14\" viewBox=\"0 0 24 24\" fill=\"none\" stroke=\"currentColor\" stroke-width=\"2\"><path d=\"M3 6h18M3 12h18M3 18h18\"/></svg></div><b>calc</b></div>\n                <div class=\"meta\">Sandbox python · numbers, dates, FX</div>\n                <div class=\"stat\" style=\"font-size:.85rem; color:rgba(255,255,255,0.6); font-family:'JetBrains Mono';\">used 3,118×</div>\n              </div>\n              <div class=\"sec-card\">\n                <div class=\"hd\"><div class=\"ic\"><svg width=\"14\" height=\"14\" viewBox=\"0 0 24 24\" fill=\"none\" stroke=\"currentColor\" stroke-width=\"2\"><rect x=\"3\" y=\"4\" width=\"18\" height=\"16\" rx=\"2\"/><path d=\"M16 2v4M8 2v4M3 10h18\"/></svg></div><b>calendar</b></div>\n                <div class=\"meta\">Read &amp; write Exchange / Google · meetings</div>\n                <div class=\"stat\" style=\"font-size:.85rem; color:rgba(255,255,255,0.6); font-family:'JetBrains Mono';\">used 408×</div>\n              </div>\n              <div class=\"sec-card\">\n                <div class=\"hd\"><div class=\"ic\"><svg width=\"14\" height=\"14\" viewBox=\"0 0 24 24\" fill=\"none\" stroke=\"currentColor\" stroke-width=\"2\"><path d=\"M21 15a2 2 0 0 1-2 2H7l-4 4V5a2 2 0 0 1 2-2h14a2 2 0 0 1 2 2z\"/></svg></div><b>ticket-create</b></div>\n                <div class=\"meta\">Create Jira / ServiceNow · attach context</div>\n                <div class=\"stat\" style=\"font-size:.85rem; color:rgba(255,255,255,0.6); font-family:'JetBrains Mono';\">used 214×</div>\n              </div>\n              <div class=\"sec-card\">\n                <div class=\"hd\"><div class=\"ic\"><svg width=\"14\" height=\"14\" viewBox=\"0 0 24 24\" fill=\"none\" stroke=\"currentColor\" stroke-width=\"2\"><path d=\"M22 2 11 13\"/><path d=\"M22 2 15 22l-4-9-9-4z\"/></svg></div><b>email-draft</b></div>\n                <div class=\"meta\">Compose · attach citations · human review</div>\n                <div class=\"stat\" style=\"font-size:.85rem; color:rgba(255,255,255,0.6); font-family:'JetBrains Mono';\">used 902×</div>\n              </div>\n              <div class=\"sec-card\">\n                <div class=\"hd\"><div class=\"ic\"><svg width=\"14\" height=\"14\" viewBox=\"0 0 24 24\" fill=\"none\" stroke=\"currentColor\" stroke-width=\"2\"><path d=\"M21 15v4a2 2 0 0 1-2 2H5a2 2 0 0 1-2-2v-4\"/><path d=\"M7 10l5 5 5-5M12 15V3\"/></svg></div><b>memo-export</b></div>\n                <div class=\"meta\">Render answer as branded PDF · sign &amp; archive</div>\n                <div class=\"stat\" style=\"font-size:.85rem; color:rgba(255,255,255,0.6); font-family:'JetBrains Mono';\">used 1,816×</div>\n              </div>\n            </div>\n          </div>\n        </div>\n      </div>\n\n      <!-- 05 GOVERNANCE -->\n      <div class=\"module\">\n        <div class=\"module-text\">\n          <div class=\"num\">05 — Governance &amp; audit</div>\n          <h3>If it can't be audited, it can't be trusted.</h3>\n          <p class=\"lead\">Every retrieval, tool call, planning step and final answer is logged with attribution. Compliance officers can replay any session, see exactly what the model saw, and export evidence for review.</p>\n          <ul>\n            <li>Append-only audit ledger · 7-year retention</li>\n            <li>Per-session replay: question, retrievals, tools, answer</li>\n            <li>Compliance dashboards · adoption · risk · accuracy</li>\n            <li>Red-team mode &amp; jailbreak monitoring</li>\n            <li>Model &amp; prompt version pinning · rollback</li>\n          </ul>\n        </div>\n        <div class=\"module-visual\">\n          <div class=\"mv-bar\"><div class=\"dots\"><i></i><i></i><i></i></div><span>Audit log · last 30 minutes</span></div>\n          <div class=\"mv-body\">\n            <div class=\"log-row\">\n              <div class=\"av a\">FA</div>\n              <div class=\"body\"><b>Fatima A.</b> · queried <i>\"federal procurement thresholds\"</i><div class=\"det\">workspace: Policy · 7 retrievals · 2 tool calls · answer cited 4 sources</div></div>\n              <div class=\"ts\">12:42</div>\n            </div>\n            <div class=\"log-row\">\n              <div class=\"av b\">SK</div>\n              <div class=\"body\"><b>System</b> · ACL denied 2 chunks for user role <i>analyst</i><div class=\"det\">doc-classified-2024-q3.pdf · workspace: Legal · expected · logged</div></div>\n              <div class=\"ts\">12:42</div>\n            </div>\n            <div class=\"log-row\">\n              <div class=\"av c\">RM</div>\n              <div class=\"body\"><b>Compliance · Reem M.</b> · exported session #18204 to evidence archive<div class=\"det\">PDF + JSON trace · signed · retention 7y</div></div>\n              <div class=\"ts\">12:38</div>\n            </div>\n            <div class=\"log-row\">\n              <div class=\"av a\">JA</div>\n              <div class=\"body\"><b>Jasem A.</b> · flagged answer #18198 for review<div class=\"det\">reason: outdated source · routed to policy reviewer</div></div>\n              <div class=\"ts\">12:31</div>\n            </div>\n            <div class=\"log-row\">\n              <div class=\"av b\">SK</div>\n              <div class=\"body\"><b>System</b> · prompt-injection attempt blocked &amp; logged<div class=\"det\">user-uploaded PDF contained instruction-override pattern · isolated</div></div>\n              <div class=\"ts\">12:24</div>\n            </div>\n          </div>\n        </div>\n      </div>\n\n    </div>\n  </div>\n</section>\n\n<!-- ============== ARCHITECTURE ============== -->\n<section class=\"section\">\n  <div class=\"container\">\n    <div class=\"section-head reveal\" style=\"margin-bottom:2.5rem;\">\n      <span class=\"eyebrow\">Under the hood</span>\n      <h2 style=\"margin-top:1rem;max-width:22ch;\">A platform you can run yourself.</h2>\n      <p class=\"lead\" style=\"max-width:62ch;\">Everything ships as containers. Bring your own GPU, your own keys, your own LDAP. We provide the platform; you keep the data.</p>\n    </div>\n\n    <div class=\"arch reveal\">\n      <svg viewBox=\"0 0 1100 460\" class=\"arch-svg\" xmlns=\"http://www.w3.org/2000/svg\">\n        <defs>\n          <marker id=\"ar-rg-arr\" viewBox=\"0 0 10 10\" refX=\"9\" refY=\"5\" markerWidth=\"6\" markerHeight=\"6\" orient=\"auto-start-reverse\"><path d=\"M0 0 L10 5 L0 10 z\" fill=\"rgba(122,240,184,0.5)\"/></marker>\n        </defs>\n\n        <!-- Tier labels -->\n        <g font-family=\"'JetBrains Mono'\" font-size=\"9\" fill=\"rgba(255,255,255,0.4)\" text-anchor=\"middle\">\n          <text x=\"120\" y=\"18\">CLIENTS</text>\n          <text x=\"420\" y=\"18\">CONTROL PLANE</text>\n          <text x=\"700\" y=\"18\">AGENT &amp; RETRIEVAL</text>\n          <text x=\"980\" y=\"18\">DATA &amp; MODELS</text>\n        </g>\n\n        <!-- Clients -->\n        <g font-family=\"'JetBrains Mono'\" font-size=\"11\" fill=\"rgba(255,255,255,0.7)\">\n          <rect x=\"20\" y=\"50\" width=\"200\" height=\"56\" rx=\"10\" fill=\"rgba(91,141,239,0.06)\" stroke=\"rgba(91,141,239,0.3)\"/>\n          <text x=\"120\" y=\"74\" text-anchor=\"middle\" fill=\"#9EBAF6\" font-weight=\"600\">Web console</text>\n          <text x=\"120\" y=\"91\" text-anchor=\"middle\" font-size=\"9\">React · streaming UI</text>\n\n          <rect x=\"20\" y=\"120\" width=\"200\" height=\"56\" rx=\"10\" fill=\"rgba(230,107,217,0.06)\" stroke=\"rgba(230,107,217,0.3)\"/>\n          <text x=\"120\" y=\"144\" text-anchor=\"middle\" fill=\"#F0A9E6\" font-weight=\"600\">Slack / Teams bot</text>\n          <text x=\"120\" y=\"161\" text-anchor=\"middle\" font-size=\"9\">in-channel · DM</text>\n\n          <rect x=\"20\" y=\"190\" width=\"200\" height=\"56\" rx=\"10\" fill=\"rgba(245,197,107,0.06)\" stroke=\"rgba(245,197,107,0.3)\"/>\n          <text x=\"120\" y=\"214\" text-anchor=\"middle\" fill=\"#F5C56B\" font-weight=\"600\">REST / SDK</text>\n          <text x=\"120\" y=\"231\" text-anchor=\"middle\" font-size=\"9\">embed in your apps</text>\n\n          <rect x=\"20\" y=\"260\" width=\"200\" height=\"56\" rx=\"10\" fill=\"rgba(122,240,184,0.06)\" stroke=\"rgba(122,240,184,0.3)\"/>\n          <text x=\"120\" y=\"284\" text-anchor=\"middle\" fill=\"#7AF0B8\" font-weight=\"600\">Compliance dash</text>\n          <text x=\"120\" y=\"301\" text-anchor=\"middle\" font-size=\"9\">audit · adoption · risk</text>\n        </g>\n\n        <!-- API gateway -->\n        <g>\n          <rect x=\"320\" y=\"120\" width=\"200\" height=\"120\" rx=\"12\" fill=\"#0E1320\" stroke=\"rgba(122,240,184,0.45)\"/>\n          <text x=\"420\" y=\"148\" text-anchor=\"middle\" fill=\"#7AF0B8\" font-family=\"'Space Grotesk'\" font-weight=\"700\" font-size=\"13\">API + Auth</text>\n          <text x=\"420\" y=\"168\" text-anchor=\"middle\" fill=\"rgba(255,255,255,0.6)\" font-family=\"'JetBrains Mono'\" font-size=\"10\">SSO · SAML · OAuth2</text>\n          <text x=\"420\" y=\"186\" text-anchor=\"middle\" fill=\"rgba(255,255,255,0.5)\" font-family=\"'JetBrains Mono'\" font-size=\"9\">rate-limit · audit</text>\n          <text x=\"420\" y=\"204\" text-anchor=\"middle\" fill=\"rgba(255,255,255,0.5)\" font-family=\"'JetBrains Mono'\" font-size=\"9\">streaming WebSocket</text>\n        </g>\n\n        <!-- Agent core -->\n        <g>\n          <rect x=\"600\" y=\"50\" width=\"200\" height=\"56\" rx=\"10\" fill=\"rgba(255,255,255,0.025)\" stroke=\"rgba(255,255,255,0.08)\"/>\n          <text x=\"700\" y=\"74\" text-anchor=\"middle\" fill=\"#F5F7FB\" font-family=\"'Space Grotesk'\" font-weight=\"600\" font-size=\"13\">Agent runtime</text>\n          <text x=\"700\" y=\"91\" text-anchor=\"middle\" fill=\"rgba(255,255,255,0.6)\" font-family=\"'JetBrains Mono'\" font-size=\"9\">plan · act · verify · reflect</text>\n\n          <rect x=\"600\" y=\"120\" width=\"200\" height=\"56\" rx=\"10\" fill=\"rgba(255,255,255,0.025)\" stroke=\"rgba(255,255,255,0.08)\"/>\n          <text x=\"700\" y=\"144\" text-anchor=\"middle\" fill=\"#F5F7FB\" font-family=\"'Space Grotesk'\" font-weight=\"600\" font-size=\"13\">Retrieval engine</text>\n          <text x=\"700\" y=\"161\" text-anchor=\"middle\" fill=\"rgba(255,255,255,0.6)\" font-family=\"'JetBrains Mono'\" font-size=\"9\">hybrid · ACL-aware · rerank</text>\n\n          <rect x=\"600\" y=\"190\" width=\"200\" height=\"56\" rx=\"10\" fill=\"rgba(255,255,255,0.025)\" stroke=\"rgba(255,255,255,0.08)\"/>\n          <text x=\"700\" y=\"214\" text-anchor=\"middle\" fill=\"#F5F7FB\" font-family=\"'Space Grotesk'\" font-weight=\"600\" font-size=\"13\">Tool registry</text>\n          <text x=\"700\" y=\"231\" text-anchor=\"middle\" fill=\"rgba(255,255,255,0.6)\" font-family=\"'JetBrains Mono'\" font-size=\"9\">sandbox · DB · email · APIs</text>\n\n          <rect x=\"600\" y=\"260\" width=\"200\" height=\"56\" rx=\"10\" fill=\"rgba(255,255,255,0.025)\" stroke=\"rgba(255,255,255,0.08)\"/>\n          <text x=\"700\" y=\"284\" text-anchor=\"middle\" fill=\"#F5F7FB\" font-family=\"'Space Grotesk'\" font-weight=\"600\" font-size=\"13\">Ingestion pipeline</text>\n          <text x=\"700\" y=\"301\" text-anchor=\"middle\" fill=\"rgba(255,255,255,0.6)\" font-family=\"'JetBrains Mono'\" font-size=\"9\">parse · OCR · chunk · embed</text>\n\n          <rect x=\"600\" y=\"330\" width=\"200\" height=\"56\" rx=\"10\" fill=\"rgba(255,255,255,0.025)\" stroke=\"rgba(255,255,255,0.08)\"/>\n          <text x=\"700\" y=\"354\" text-anchor=\"middle\" fill=\"#F5F7FB\" font-family=\"'Space Grotesk'\" font-weight=\"600\" font-size=\"13\">Eval &amp; safety</text>\n          <text x=\"700\" y=\"371\" text-anchor=\"middle\" fill=\"rgba(255,255,255,0.6)\" font-family=\"'JetBrains Mono'\" font-size=\"9\">PII · jailbreak · self-verify</text>\n        </g>\n\n        <!-- Data layer -->\n        <g font-family=\"'JetBrains Mono'\" font-size=\"10\" fill=\"rgba(255,255,255,0.7)\">\n          <rect x=\"880\" y=\"50\"  width=\"200\" height=\"56\" rx=\"10\" fill=\"rgba(91,141,239,0.06)\" stroke=\"rgba(91,141,239,0.3)\"/>\n          <text x=\"980\" y=\"74\" text-anchor=\"middle\" fill=\"#9EBAF6\" font-family=\"'Space Grotesk'\" font-weight=\"600\" font-size=\"13\">Vector store</text>\n          <text x=\"980\" y=\"91\" text-anchor=\"middle\">pgvector · Qdrant</text>\n\n          <rect x=\"880\" y=\"120\" width=\"200\" height=\"56\" rx=\"10\" fill=\"rgba(91,141,239,0.06)\" stroke=\"rgba(91,141,239,0.3)\"/>\n          <text x=\"980\" y=\"144\" text-anchor=\"middle\" fill=\"#9EBAF6\" font-family=\"'Space Grotesk'\" font-weight=\"600\" font-size=\"13\">BM25 · OpenSearch</text>\n          <text x=\"980\" y=\"161\" text-anchor=\"middle\">keyword · facet</text>\n\n          <rect x=\"880\" y=\"190\" width=\"200\" height=\"56\" rx=\"10\" fill=\"rgba(230,107,217,0.06)\" stroke=\"rgba(230,107,217,0.3)\"/>\n          <text x=\"980\" y=\"214\" text-anchor=\"middle\" fill=\"#F0A9E6\" font-family=\"'Space Grotesk'\" font-weight=\"600\" font-size=\"13\">Postgres + ACLs</text>\n          <text x=\"980\" y=\"231\" text-anchor=\"middle\">tenants · roles · chunks</text>\n\n          <rect x=\"880\" y=\"260\" width=\"200\" height=\"56\" rx=\"10\" fill=\"rgba(245,197,107,0.06)\" stroke=\"rgba(245,197,107,0.3)\"/>\n          <text x=\"980\" y=\"284\" text-anchor=\"middle\" fill=\"#F5C56B\" font-family=\"'Space Grotesk'\" font-weight=\"600\" font-size=\"13\">Object store</text>\n          <text x=\"980\" y=\"301\" text-anchor=\"middle\">source docs · evidence</text>\n\n          <rect x=\"880\" y=\"330\" width=\"200\" height=\"56\" rx=\"10\" fill=\"rgba(122,240,184,0.06)\" stroke=\"rgba(122,240,184,0.3)\"/>\n          <text x=\"980\" y=\"354\" text-anchor=\"middle\" fill=\"#7AF0B8\" font-family=\"'Space Grotesk'\" font-weight=\"600\" font-size=\"13\">Model · GPU</text>\n          <text x=\"980\" y=\"371\" text-anchor=\"middle\">Llama 3 · Qwen · local</text>\n        </g>\n\n        <!-- arrows -->\n        <g stroke=\"rgba(122,240,184,0.4)\" stroke-width=\"1.4\" fill=\"none\" marker-end=\"url(#ar-rg-arr)\">\n          <path d=\"M220 78  C 270 78, 290 150, 320 165\"/>\n          <path d=\"M220 148 C 270 148, 295 165, 320 175\"/>\n          <path d=\"M220 218 C 270 218, 295 195, 320 188\"/>\n          <path d=\"M220 288 C 270 288, 295 215, 320 205\"/>\n        </g>\n        <g stroke=\"rgba(255,255,255,0.18)\" stroke-width=\"1.4\" fill=\"none\" marker-end=\"url(#ar-rg-arr)\">\n          <path d=\"M520 150 L 600 78\"/>\n          <path d=\"M520 168 L 600 148\"/>\n          <path d=\"M520 188 L 600 218\"/>\n          <path d=\"M520 205 L 600 288\"/>\n          <path d=\"M520 220 L 600 358\"/>\n        </g>\n        <g stroke=\"rgba(91,141,239,0.35)\" stroke-width=\"1.4\" fill=\"none\" marker-end=\"url(#ar-rg-arr)\">\n          <path d=\"M800 78  L 880 78\"/>\n          <path d=\"M800 148 L 880 148\"/>\n          <path d=\"M800 218 L 880 218\"/>\n          <path d=\"M800 288 L 880 288\"/>\n          <path d=\"M800 358 L 880 358\"/>\n        </g>\n      </svg>\n    </div>\n  </div>\n</section>\n\n<!-- ============== DEPLOYMENTS ============== -->\n<section class=\"section\">\n  <div class=\"container\">\n    <div class=\"section-head reveal\" style=\"margin-bottom:2.5rem;\">\n      <span class=\"eyebrow\">In production</span>\n      <h2 style=\"margin-top:1rem;max-width:22ch;\">Three deployments. Three industries. One platform.</h2>\n      <p class=\"lead\" style=\"max-width:62ch;\">Anonymized at the client's request. Sector, scale and outcomes are real and verifiable on request under NDA.</p>\n    </div>\n\n    <div class=\"stories reveal-stagger\">\n\n      <article class=\"story\">\n        <div class=\"story-head\">\n          <span class=\"seg-tag\">Government · Policy</span>\n          <h3>Policy analysts get an answer in 90 seconds, not an afternoon.</h3>\n          <span class=\"where\">Federal ministry · 14 analysts · 3,420 docs</span>\n        </div>\n        <div class=\"story-body\">\n          <p>A federal policy unit replaced the practice of \"ask the senior analyst\" with a sovereign on-prem deployment. The corpus: every regulation, decree, circular and amendment going back 12 years. Air-gapped; nothing leaves the perimeter.</p>\n          <p class=\"quote\">\"Junior analysts now produce briefings the seniors can sign without rewriting them. The citations are the unlock.\"</p>\n          <p class=\"quote-by\">— director, policy unit</p>\n          <div class=\"story-kpis\">\n            <div class=\"story-kpi\"><div class=\"v\">12×</div><div class=\"l\">faster briefing turnaround</div></div>\n            <div class=\"story-kpi\"><div class=\"v\">94%</div><div class=\"l\">citation precision</div></div>\n            <div class=\"story-kpi\"><div class=\"v\">100%</div><div class=\"l\">on-prem · air-gapped</div></div>\n            <div class=\"story-kpi\"><div class=\"v\">0</div><div class=\"l\">data egress events</div></div>\n          </div>\n        </div>\n      </article>\n\n      <article class=\"story\">\n        <div class=\"story-head\">\n          <span class=\"seg-tag\">Enterprise · Legal</span>\n          <h3>Contract review at the speed of partnership.</h3>\n          <span class=\"where\">In-house legal · 28 lawyers · 180k contracts</span>\n        </div>\n        <div class=\"story-body\">\n          <p>A regional conglomerate's legal team uses the platform to triage incoming contracts against their own playbook — flagging deviations, citing the playbook clause, and drafting a redline memo for the partner to review.</p>\n          <p class=\"quote\">\"It does the first read of every contract that lands in our inbox. The partners get to spend their time on the hard 10%.\"</p>\n          <p class=\"quote-by\">— general counsel</p>\n          <div class=\"story-kpis\">\n            <div class=\"story-kpi\"><div class=\"v\">−74%</div><div class=\"l\">first-pass review time</div></div>\n            <div class=\"story-kpi\"><div class=\"v\">+4.1×</div><div class=\"l\">contracts reviewed / week</div></div>\n            <div class=\"story-kpi\"><div class=\"v\">96%</div><div class=\"l\">deviation-flag accuracy</div></div>\n            <div class=\"story-kpi\"><div class=\"v\">7-yr</div><div class=\"l\">audit retention</div></div>\n          </div>\n        </div>\n      </article>\n\n      <article class=\"story\">\n        <div class=\"story-head\">\n          <span class=\"seg-tag\">Enterprise · Customer support</span>\n          <h3>Tier-1 support agents that actually know the product.</h3>\n          <span class=\"where\">Telco · 220 agents · 42k KB articles</span>\n        </div>\n        <div class=\"story-body\">\n          <p>A regional telco's tier-1 support agents have the assistant beside their CRM. It reads the customer's account context, the ticket, the device manual and the latest network bulletin — drafts a response, cites the article, and routes to tier-2 only when needed.</p>\n          <p class=\"quote\">\"Our average handle time dropped, and our customer-satisfaction score went up. Both at once. Rare.\"</p>\n          <p class=\"quote-by\">— head of customer operations</p>\n          <div class=\"story-kpis\">\n            <div class=\"story-kpi\"><div class=\"v\">−38%</div><div class=\"l\">avg handle time</div></div>\n            <div class=\"story-kpi\"><div class=\"v\">+11pt</div><div class=\"l\">CSAT improvement</div></div>\n            <div class=\"story-kpi\"><div class=\"v\">−52%</div><div class=\"l\">escalations to tier-2</div></div>\n            <div class=\"story-kpi\"><div class=\"v\">3 wks</div><div class=\"l\">to live with 220 agents</div></div>\n          </div>\n        </div>\n      </article>\n\n    </div>\n  </div>\n</section>\n\n<!-- ============== IMPLEMENTATION TIMELINE ============== -->\n<section class=\"section\">\n  <div class=\"container split reveal-stagger\" style=\"align-items:flex-start;gap:3rem;\">\n    <div>\n      <span class=\"eyebrow\">Implementation</span>\n      <h2 style=\"margin-top:1rem;max-width:18ch;\">Live in 6 weeks. Cautiously.</h2>\n      <p style=\"margin-top:1.25rem;color:var(--mist-80);\">Our standard rollout: discovery, secure environment provisioning, corpus ingestion, evaluation, pilot, and a 30-day stabilisation. We move quickly on infrastructure and slowly on trust — exactly the right pace for sensitive data.</p>\n      <a href=\"/contact\" class=\"btn btn-primary\" style=\"margin-top:1.5rem;\">Talk through your rollout\n        <svg class=\"arrow\" viewBox=\"0 0 24 24\" fill=\"none\" stroke=\"currentColor\" stroke-width=\"2\"><path d=\"M5 12h14M13 5l7 7-7 7\"/></svg>\n      </a>\n    </div>\n\n    <div class=\"timeline\">\n      <div class=\"tl-step\">\n        <div class=\"wk\">Week 1 · Discovery</div>\n        <h4>Map the corpus &amp; the questions</h4>\n        <p>Sources, document types, ACL model, target use-cases, evaluation set. Threat model and deployment topology agreed in writing.</p>\n      </div>\n      <div class=\"tl-step\">\n        <div class=\"wk\">Week 2 · Secure provisioning</div>\n        <h4>Stand up the environment</h4>\n        <p>On-prem cluster (or sovereign cloud) provisioned. SSO &amp; LDAP wired. KMS keys handed over. Network ingress &amp; egress locked down.</p>\n      </div>\n      <div class=\"tl-step\">\n        <div class=\"wk\">Week 3 · Ingestion</div>\n        <h4>Index the corpus</h4>\n        <p>Connectors live. ACLs imported and verified. First-pass index complete. Initial retrieval evaluation against the gold set.</p>\n      </div>\n      <div class=\"tl-step\">\n        <div class=\"wk\">Week 4 · Tuning</div>\n        <h4>Tune retrieval &amp; agent</h4>\n        <p>Reranker tuned. Custom tools added. Domain-specific prompts. Evaluation iterated until citation precision passes the bar.</p>\n      </div>\n      <div class=\"tl-step\">\n        <div class=\"wk\">Week 5 · Pilot</div>\n        <h4>Pilot with 5–10 users</h4>\n        <p>Real users, daily review of every session. Issues fixed in hours. Adoption coached. Compliance dashboard handed to risk team.</p>\n      </div>\n      <div class=\"tl-step\">\n        <div class=\"wk\">Week 6 · Roll-out</div>\n        <h4>Open to the team</h4>\n        <p>Wider rollout. Training kits in-platform. We stay close — daily, then weekly — for 30 days, then transition to support cadence.</p>\n      </div>\n    </div>\n  </div>\n</section>\n\n<!-- ============== COMPLIANCE BADGES ============== -->\n<section class=\"section\">\n  <div class=\"container\">\n    <div class=\"section-head reveal\" style=\"margin-bottom:2rem;\">\n      <span class=\"eyebrow\">Compliance</span>\n      <h2 style=\"margin-top:1rem;max-width:22ch;\">Built for regulated environments.</h2>\n      <p class=\"lead\" style=\"max-width:62ch;\">We design to the strictest regulator in the room. SOC 2, ISO 27001, UAE NESA, GDPR-equivalent data residency, and sector-specific frameworks on request.</p>\n    </div>\n\n    <div class=\"compl-grid reveal-stagger\">\n      <div class=\"compl\"><div class=\"lo\">SOC 2 · Type II</div><div class=\"ty\">Security</div></div>\n      <div class=\"compl\"><div class=\"lo\">ISO 27001</div><div class=\"ty\">Infosec</div></div>\n      <div class=\"compl\"><div class=\"lo\">UAE NESA</div><div class=\"ty\">Sovereign</div></div>\n      <div class=\"compl\"><div class=\"lo\">GDPR-equiv</div><div class=\"ty\">Privacy</div></div>\n      <div class=\"compl\"><div class=\"lo\">UAE PDPL</div><div class=\"ty\">Privacy</div></div>\n      <div class=\"compl\"><div class=\"lo\">HIPAA-ready</div><div class=\"ty\">Healthcare</div></div>\n      <div class=\"compl\"><div class=\"lo\">PCI-DSS</div><div class=\"ty\">Payments</div></div>\n      <div class=\"compl\"><div class=\"lo\">FedRAMP-style</div><div class=\"ty\">Gov-grade</div></div>\n      <div class=\"compl\"><div class=\"lo\">AES-256</div><div class=\"ty\">Encryption</div></div>\n      <div class=\"compl\"><div class=\"lo\">EU AI Act</div><div class=\"ty\">AI · ready</div></div>\n    </div>\n  </div>\n</section>\n\n<!-- ============== FAQ ============== -->\n<section class=\"section\">\n  <div class=\"container split reveal-stagger\" style=\"align-items:flex-start; gap:3rem;\">\n    <div>\n      <span class=\"eyebrow\">Common questions</span>\n      <h2 style=\"margin-top:1rem;max-width:18ch;\">The things every CIO asks.</h2>\n      <p style=\"margin-top:1.25rem;color:var(--mist-80);\">If yours isn't here, ask us directly — we welcome the security questionnaire.</p>\n      <a href=\"/contact\" class=\"btn btn-outline\" style=\"margin-top:1.25rem;\">Send your questionnaire</a>\n    </div>\n\n    <div class=\"faq\">\n      <details>\n        <summary>Does our data ever leave our perimeter?</summary>\n        <p>No. The default deployment is on-prem or sovereign-cloud, single-tenant, with all model weights, embeddings and source documents resident inside your boundary. There is no required outbound call. For air-gapped clients we deliver a fully offline release artefact.</p>\n      </details>\n      <details>\n        <summary>Which model do you use? Can we bring our own?</summary>\n        <p>By default we deploy open-weight models (Llama 3, Qwen, Mistral families) — they are competitive on retrieval-heavy workloads and they run inside your perimeter. Clients can also bring their own model: Azure OpenAI in a private link, an internal fine-tune, or a sovereign endpoint. The agent runtime is model-agnostic.</p>\n      </details>\n      <details>\n        <summary>How do you prevent hallucinations?</summary>\n        <p>Three layers. First, the retrieval is good — strong recall on the right document. Second, the agent self-verifies: every claim in the draft is checked against its cited source before the answer is shown. Third, the UI never hides the source — users see the chunk, not just the citation. On benchmarks our hallucination rate sits below 1%.</p>\n      </details>\n      <details>\n        <summary>How are document permissions handled?</summary>\n        <p>Permissions are inherited from the source system at ingest time and stored at the chunk level. Every retrieval is filtered by the asking user's effective permissions before the model sees anything. The model can never retrieve a chunk the user is not already entitled to read.</p>\n      </details>\n      <details>\n        <summary>What about prompt injection from uploaded documents?</summary>\n        <p>We treat all retrieved text as untrusted. Tool execution is sandboxed; tool calls require structured arguments, not free-form prompts. Documents are scanned for instruction-override patterns at ingest. Sensitive tools (email, ticket creation, code execution) require explicit user confirmation in the UI.</p>\n      </details>\n      <details>\n        <summary>Can we audit what the model said and saw?</summary>\n        <p>Yes — every session is replayable. Compliance officers see the question, the retrieval results (including filtered-out items), every tool call and its arguments, the draft, the verified-claim mapping, and the final answer. Audit ledger is append-only with 7-year retention by default.</p>\n      </details>\n      <details>\n        <summary>What's pricing?</summary>\n        <p>A platform subscription based on user-seats and corpus size, plus a one-time deployment fee. Sovereign / air-gapped contracts are quoted separately because the support model is different. We share a worked example in the discovery call — no obligation.</p>\n      </details>\n    </div>\n  </div>\n</section>\n\n<!-- ============== CTA ============== -->\n<section class=\"section\">\n  <div class=\"container\">\n    <div class=\"cta-banner reveal\">\n      <div class=\"cta-glow\" aria-hidden=\"true\"></div>\n      <span class=\"eyebrow\" style=\"justify-content:center;\">Book a private walkthrough</span>\n      <h2 style=\"margin-top:1rem;\">See it on your corpus.</h2>\n      <p>45 minutes. We'll demo the platform on a sanitised slice of your real documents — not a sample dataset.</p>\n      <div style=\"display:flex; gap:.85rem; justify-content:center; flex-wrap:wrap; margin-top:1.5rem;\">\n        <a href=\"/contact\" class=\"btn btn-primary btn-lg\">Book a private demo\n          <svg class=\"arrow\" viewBox=\"0 0 24 24\" fill=\"none\" stroke=\"currentColor\" stroke-width=\"2\"><path d=\"M5 12h14M13 5l7 7-7 7\"/></svg>\n        </a>\n        <a href=\"/contact\" class=\"btn btn-outline btn-lg\">Send security questionnaire</a>\n      </div>\n    </div>\n  </div>\n</section>";

export default function SolutionAgenticRagPage() {
  return (
    <>
      <JsonLd data={jsonLd} />
      <LegacyEnhancers />
      <div dangerouslySetInnerHTML={{ __html: body }} />
    </>
  );
}
